import{_ as a,o as t,c as r,a0 as s}from"./chunks/framework.jwovEGr5.js";const d=JSON.parse('{"title":"Re:Zero kara Hajimeru Isekai Seikatsu 4th Season — MyAnimeList Entry","description":"","frontmatter":{"type":"source","title":"Re:Zero kara Hajimeru Isekai Seikatsu 4th Season — MyAnimeList Entry","created":"2026-07-10T00:00:00.000Z","updated":"2026-07-10T00:00:00.000Z","tags":["anime","re-zero","isekai","fantasy"],"related":["re-zero-4th-season","subaru-natsuki","rem","authority-of-gluttony","pleiades-watchtower","sage-shaula"],"sources":["anime/61316.md"],"authors":[],"year":2026,"url":"https://myanimelist.net/anime/61316","venue":"MyAnimeList","date":"2026-07-10T00:00:00.000Z"},"headers":[],"relativePath":"sources/5-anime--5-61316--b37doc.md","filePath":"sources/5-anime--5-61316--b37doc.md"}'),i={name:"sources/5-anime--5-61316--b37doc.md"};function o(n,e,u,l,h,m){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="re-zero-kara-hajimeru-isekai-seikatsu-4th-season-—-myanimelist-entry" tabindex="-1">Re:Zero kara Hajimeru Isekai Seikatsu 4th Season — MyAnimeList Entry <a class="header-anchor" href="#re-zero-kara-hajimeru-isekai-seikatsu-4th-season-—-myanimelist-entry" aria-label="Permalink to &quot;Re:Zero kara Hajimeru Isekai Seikatsu 4th Season — MyAnimeList Entry&quot;">​</a></h1><p>《Re:Zero kara Hajimeru Isekai Seikatsu 4th Season》（Re:ZERO -Starting Life in Another World- Season 4）是2026年播出的日本动画，改编自长月达平的同名轻小说系列。本季共19集，目前正在播出中，在MyAnimeList上获得9.18的评分。类型为剧情、奇幻、悬疑。</p><h2 id="剧情概要" tabindex="-1">剧情概要 <a class="header-anchor" href="#剧情概要" aria-label="Permalink to &quot;剧情概要&quot;">​</a></h2><p>在水门都市普利斯特拉（Priestella）的致命战斗中，菜月昴（<a href="/entities/菜月昴-subaru-natsuki.html">subaru-natsuki</a>）和他的盟友勉强取得了胜利——但胜利的代价极为惨重。通过&quot;暴食&quot;权能（<a href="/concepts/暴食权能-authority-of-gluttony.html">authority-of-gluttony</a>），雷姆（<a href="/entities/雷姆-rem.html">rem</a>）被置于假死状态，库珥修的记忆乃至尤里乌斯的名字都被吞噬。在寻找解救他们的方法时，昴得知了&quot;贤者&quot;莎缇拉（<a href="/entities/贤者莎缇拉-sage-shaula.html">sage-shaula</a>）的存在——一个据称拥有所有知识的全知存在。他的下一个目的地是贤者之塔（<a href="/entities/贤者之塔-pleiades-watchtower.html">pleiades-watchtower</a>），即贤者的居所，也是旅程的最远方。</p><h2 id="关键信息" tabindex="-1">关键信息 <a class="header-anchor" href="#关键信息" aria-label="Permalink to &quot;关键信息&quot;">​</a></h2><ul><li><strong>作品ID (MAL)</strong>: 61316</li><li><strong>评分</strong>: 9.18</li><li><strong>集数</strong>: 19</li><li><strong>状态</strong>: 播出中</li><li><strong>年份</strong>: 2026</li><li><strong>类型</strong>: Drama, Fantasy, Suspense</li></ul>',6)])])}const k=a(i,[["render",o]]);export{d as __pageData,k as default};
